import React, { useState, useEffect, useCallback } from 'react';
import { Map, Polyline, CustomOverlayMap, useKakaoLoader } from 'react-kakao-maps-sdk';
import api from '../api/axios';

// ── 타입 ──────────────────────────────────────────────
interface LatLng { lat: number; lng: number; }

interface RunningGoal {
  id?: number;
  year: number;
  month: number;
  targetCount: number;
  targetDistanceKm?: number;
  achievedCount: number;
  achievedDistanceKm: number;
  streak: number;
}

interface RunningRecord {
  id?: number;
  runDate: string;
  ran: boolean;
  distanceKm?: number;
  memo?: string;
  routeJson?: string;
}

// ── Haversine 거리 계산 (km) ──────────────────────────
const haversine = (a: LatLng, b: LatLng) => {
  const R = 6371;
  const dLat = (b.lat - a.lat) * Math.PI / 180;
  const dLng = (b.lng - a.lng) * Math.PI / 180;
  const sin2 = Math.sin(dLat / 2) ** 2 +
    Math.cos(a.lat * Math.PI / 180) * Math.cos(b.lat * Math.PI / 180) * Math.sin(dLng / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(sin2), Math.sqrt(1 - sin2));
};

// 경로 전체 거리 계산
const calcTotalDistance = (path: LatLng[]) => {
  let total = 0;
  for (let i = 1; i < path.length; i++) total += haversine(path[i - 1], path[i]);
  return total;
};

// 1km 단위 마커 위치 계산
const calcKmMarkers = (path: LatLng[]) => {
  const markers: { km: number; pos: LatLng }[] = [];
  if (path.length < 2) return markers;
  let cumDist = 0;
  let nextKm = 1;
  for (let i = 1; i < path.length; i++) {
    const segDist = haversine(path[i - 1], path[i]);
    while (cumDist + segDist >= nextKm) {
      const ratio = (nextKm - cumDist) / segDist;
      markers.push({
        km: nextKm,
        pos: {
          lat: path[i - 1].lat + ratio * (path[i].lat - path[i - 1].lat),
          lng: path[i - 1].lng + ratio * (path[i].lng - path[i - 1].lng),
        },
      });
      nextKm++;
    }
    cumDist += segDist;
  }
  return markers;
};

const today = new Date();
const todayStr = today.toISOString().split('T')[0];

// ── 메인 컴포넌트 ─────────────────────────────────────
export const RunningPage = () => {
  useKakaoLoader({
    appkey: process.env.REACT_APP_KAKAO_MAP_KEY || '',
    libraries: [],
  });

  const now = new Date();
  const [ym, setYm] = useState({ year: now.getFullYear(), month: now.getMonth() + 1 });
  const { year, month } = ym;

  const [goal, setGoal] = useState<RunningGoal | null>(null);
  const [records, setRecords] = useState<Record<string, RunningRecord>>({});
  const [showGoalModal, setShowGoalModal] = useState(false);
  const [selectedDate, setSelectedDate] = useState<string | null>(null);

  // 목표 설정 폼
  const [goalForm, setGoalForm] = useState({ targetCount: 12, targetDistanceKm: '' });

  // 기록 모달
  const [recForm, setRecForm] = useState<{
    ran: boolean; distanceKm: string; memo: string; path: LatLng[];
  }>({ ran: true, distanceKm: '', memo: '', path: [] });

  const fetchData = useCallback(async (y: number, m: number) => {
    const [goalRes, recsRes] = await Promise.allSettled([
      api.get(`/running/goal?year=${y}&month=${m}`),
      api.get(`/running/records?year=${y}&month=${m}`),
    ]);
    if (goalRes.status === 'fulfilled' && goalRes.value.data.data) {
      setGoal(goalRes.value.data.data);
    } else {
      setGoal(null);
    }
    if (recsRes.status === 'fulfilled') {
      const map: Record<string, RunningRecord> = {};
      (recsRes.value.data.data || []).forEach((r: RunningRecord) => { map[r.runDate] = r; });
      setRecords(map);
    }
  }, []);

  useEffect(() => { fetchData(year, month); }, [year, month, fetchData]);

  const moveMonth = (delta: number) => {
    setYm(prev => {
      let m = prev.month + delta;
      let y = prev.year;
      if (m > 12) { m = 1; y++; }
      if (m < 1) { m = 12; y--; }
      return { year: y, month: m };
    });
  };

  // 달력 그리드
  const firstDay = new Date(year, month - 1, 1).getDay();
  const daysInMonth = new Date(year, month, 0).getDate();
  const cells: (number | null)[] = [
    ...Array(firstDay).fill(null),
    ...Array.from({ length: daysInMonth }, (_, i) => i + 1),
  ];
  while (cells.length % 7 !== 0) cells.push(null);

  const dateStr = (day: number) =>
    `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

  const openRecord = (ds: string) => {
    const rec = records[ds];
    setRecForm({
      ran: rec?.ran ?? true,
      distanceKm: rec?.distanceKm != null ? String(rec.distanceKm) : '',
      memo: rec?.memo || '',
      path: rec?.routeJson ? JSON.parse(rec.routeJson) : [],
    });
    setSelectedDate(ds);
  };

  const saveRecord = async () => {
    if (!selectedDate) return;
    const path = recForm.path;
    const dist = recForm.ran && path.length > 1
      ? Math.round(calcTotalDistance(path) * 100) / 100
      : recForm.distanceKm ? parseFloat(recForm.distanceKm) : undefined;

    await api.post('/running/record', {
      runDate: selectedDate,
      ran: recForm.ran,
      distanceKm: dist,
      memo: recForm.memo,
      routeJson: path.length > 0 ? JSON.stringify(path) : null,
    });
    setSelectedDate(null);
    fetchData(year, month);
  };

  const saveGoal = async () => {
    await api.post('/running/goal', {
      year,
      month,
      targetCount: goalForm.targetCount,
      targetDistanceKm: goalForm.targetDistanceKm ? parseFloat(goalForm.targetDistanceKm) : null,
    });
    setShowGoalModal(false);
    fetchData(year, month);
  };

  const totalDist = calcTotalDistance(recForm.path);
  const kmMarkers = calcKmMarkers(recForm.path);

  return (
    <div className="flex flex-col gap-6">

      {/* ── 헤더 ── */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-3">
          <button onClick={() => moveMonth(-1)}
            className="w-9 h-9 flex items-center justify-center rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 text-xl">‹</button>
          <h1 className="text-2xl font-bold dark:text-dark-text min-w-[140px] text-center">
            {year}년 {month}월
          </h1>
          <button onClick={() => moveMonth(1)}
            className="w-9 h-9 flex items-center justify-center rounded-lg hover:bg-slate-100 dark:hover:bg-slate-800 text-slate-400 text-xl">›</button>
        </div>
        <button
          onClick={() => {
            setGoalForm({
              targetCount: goal?.targetCount ?? 12,
              targetDistanceKm: goal?.targetDistanceKm != null ? String(goal.targetDistanceKm) : '',
            });
            setShowGoalModal(true);
          }}
          className="text-sm px-4 py-2 bg-primary-500 text-white rounded-lg hover:bg-primary-600 transition-colors"
        >
          목표 설정
        </button>
      </div>

      {/* ── 목표 달성 카드 ── */}
      {goal ? (
        <div className="bg-white dark:bg-dark-card rounded-xl border border-slate-200 dark:border-dark-border p-5">
          <div className="flex items-center justify-between mb-4">
            <div>
              <p className="text-sm text-slate-400 dark:text-slate-500 mb-1">이번 달 목표</p>
              <p className="text-2xl font-bold dark:text-dark-text">
                {goal.achievedCount}
                <span className="text-slate-400 dark:text-slate-500 text-base font-normal"> / {goal.targetCount}회</span>
              </p>
            </div>
            <div className="text-right">
              {goal.streak > 0 && (
                <p className="text-2xl font-bold text-orange-500">🔥 {goal.streak}일 연속</p>
              )}
              {goal.targetDistanceKm && (
                <p className="text-sm text-slate-400 dark:text-slate-500 mt-1">
                  거리 {goal.achievedDistanceKm}km / {goal.targetDistanceKm}km
                </p>
              )}
            </div>
          </div>

          {/* 횟수 달성률 바 */}
          <div className="mb-2">
            <div className="flex justify-between text-xs text-slate-400 mb-1">
              <span>달성률</span>
              <span>{Math.min(100, Math.round((goal.achievedCount / goal.targetCount) * 100))}%</span>
            </div>
            <div className="w-full h-3 bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
              <div
                className="h-3 rounded-full bg-primary-500 transition-all"
                style={{ width: `${Math.min(100, (goal.achievedCount / goal.targetCount) * 100)}%` }}
              />
            </div>
          </div>

          {/* 거리 달성률 바 */}
          {goal.targetDistanceKm && (
            <div>
              <div className="flex justify-between text-xs text-slate-400 mb-1">
                <span>거리 달성률</span>
                <span>{Math.min(100, Math.round((goal.achievedDistanceKm / goal.targetDistanceKm) * 100))}%</span>
              </div>
              <div className="w-full h-3 bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
                <div
                  className="h-3 rounded-full bg-teal-500 transition-all"
                  style={{ width: `${Math.min(100, (goal.achievedDistanceKm / goal.targetDistanceKm) * 100)}%` }}
                />
              </div>
            </div>
          )}
        </div>
      ) : (
        <div className="bg-white dark:bg-dark-card rounded-xl border border-dashed border-slate-300 dark:border-slate-700 p-6 text-center">
          <p className="text-slate-400 dark:text-slate-500 text-sm mb-3">이번 달 운동 목표를 설정해보세요</p>
          <button
            onClick={() => { setGoalForm({ targetCount: 12, targetDistanceKm: '' }); setShowGoalModal(true); }}
            className="text-sm px-4 py-2 bg-primary-500 text-white rounded-lg hover:bg-primary-600 transition-colors"
          >
            목표 설정하기
          </button>
        </div>
      )}

      {/* ── 달력 ── */}
      <div className="bg-white dark:bg-dark-card rounded-xl border border-slate-200 dark:border-dark-border overflow-hidden">
        {/* 요일 헤더 */}
        <div className="grid grid-cols-7 border-b border-slate-200 dark:border-dark-border">
          {['일', '월', '화', '수', '목', '금', '토'].map((d, i) => (
            <div key={d} className={`py-3 text-center text-xs font-bold ${i === 0 ? 'text-red-400' : i === 6 ? 'text-blue-400' : 'text-slate-400 dark:text-slate-500'}`}>
              {d}
            </div>
          ))}
        </div>

        {/* 날짜 셀 */}
        <div className="grid grid-cols-7">
          {cells.map((day, idx) => {
            if (day === null) return (
              <div key={`e-${idx}`} className="h-20 border-b border-r border-slate-100 dark:border-dark-border [&:nth-child(7n)]:border-r-0" />
            );
            const ds = dateStr(day);
            const rec = records[ds];
            const isToday = ds === todayStr;
            const col = idx % 7;
            const isFuture = ds > todayStr;

            return (
              <div
                key={ds}
                onClick={() => !isFuture && openRecord(ds)}
                className={`h-20 border-b border-r border-slate-100 dark:border-dark-border [&:nth-child(7n)]:border-r-0 p-2 flex flex-col gap-1
                  ${isFuture ? 'opacity-40 cursor-default' : 'cursor-pointer hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors'}
                  ${rec?.ran === true ? 'bg-green-50 dark:bg-green-900/10' : ''}
                  ${rec?.ran === false ? 'bg-red-50 dark:bg-red-900/10' : ''}
                `}
              >
                <span className={`text-sm font-bold w-7 h-7 flex items-center justify-center rounded-full self-start
                  ${isToday ? 'bg-primary-500 text-white' : col === 0 ? 'text-red-400' : col === 6 ? 'text-blue-400' : 'text-slate-700 dark:text-dark-text'}`}>
                  {day}
                </span>
                {rec?.ran === true && (
                  <div className="flex flex-col gap-0.5">
                    <span className="text-xs text-green-600 dark:text-green-400 font-medium">✅ 뜀</span>
                    {rec.distanceKm && (
                      <span className="text-xs text-slate-400 dark:text-slate-500">{rec.distanceKm}km</span>
                    )}
                  </div>
                )}
                {rec?.ran === false && (
                  <span className="text-xs text-red-400">❌ 쉼</span>
                )}
              </div>
            );
          })}
        </div>
      </div>

      {/* ── 범례 ── */}
      <div className="flex items-center gap-6 text-xs text-slate-400 dark:text-slate-500">
        <div className="flex items-center gap-1.5">
          <span className="inline-block w-3 h-3 rounded-sm bg-green-200 dark:bg-green-900/40" />
          뛴 날
        </div>
        <div className="flex items-center gap-1.5">
          <span className="inline-block w-3 h-3 rounded-sm bg-red-200 dark:bg-red-900/40" />
          쉰 날
        </div>
        <div className="flex items-center gap-1.5">
          <span className="inline-block w-3 h-3 rounded-sm bg-slate-100 dark:bg-slate-800" />
          미기록
        </div>
      </div>

      {/* ── 기록 모달 ── */}
      {selectedDate && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
          <div className="bg-white dark:bg-dark-card rounded-2xl w-full max-w-2xl max-h-[90vh] overflow-y-auto shadow-2xl">
            <div className="p-6 border-b border-slate-200 dark:border-dark-border flex items-center justify-between">
              <h2 className="text-lg font-bold dark:text-dark-text">{selectedDate} 운동 기록</h2>
              <button onClick={() => setSelectedDate(null)} className="text-slate-400 hover:text-slate-600 text-xl">✕</button>
            </div>

            <div className="p-6 flex flex-col gap-5">
              {/* 뛰었는지 여부 */}
              <div className="flex gap-3">
                <button
                  onClick={() => setRecForm(p => ({ ...p, ran: true }))}
                  className={`flex-1 py-3 rounded-xl font-semibold transition-colors ${recForm.ran ? 'bg-green-500 text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-500'}`}
                >
                  ✅ 뛰었어요
                </button>
                <button
                  onClick={() => setRecForm(p => ({ ...p, ran: false }))}
                  className={`flex-1 py-3 rounded-xl font-semibold transition-colors ${!recForm.ran ? 'bg-red-400 text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-500'}`}
                >
                  ❌ 쉬었어요
                </button>
              </div>

              {recForm.ran && (
                <>
                  {/* 카카오 지도 - 경로 그리기 */}
                  <div>
                    <div className="flex items-center justify-between mb-2">
                      <p className="text-sm font-semibold dark:text-dark-text">경로 그리기</p>
                      <div className="flex items-center gap-3 text-xs text-slate-400">
                        <span>총 거리: <strong className="text-primary-500">{totalDist.toFixed(2)}km</strong></span>
                        {recForm.path.length > 0 && (
                          <button
                            onClick={() => setRecForm(p => ({ ...p, path: [] }))}
                            className="text-red-400 hover:text-red-600"
                          >
                            초기화
                          </button>
                        )}
                      </div>
                    </div>
                    <p className="text-xs text-slate-400 dark:text-slate-500 mb-2">지도를 클릭하여 경로를 그리세요. 1km마다 자동 표시됩니다.</p>
                    <div className="rounded-xl overflow-hidden border border-slate-200 dark:border-slate-700">
                      <Map
                        center={{ lat: 37.5665, lng: 126.9780 }}
                        style={{ width: '100%', height: '320px' }}
                        level={4}
                        onClick={(_map, e) => {
                          const pos: LatLng = { lat: e.latLng.getLat(), lng: e.latLng.getLng() };
                          setRecForm(p => ({ ...p, path: [...p.path, pos] }));
                        }}
                      >
                        {/* 경로 선 */}
                        {recForm.path.length > 1 && (
                          <Polyline
                            path={recForm.path}
                            strokeWeight={4}
                            strokeColor="#6366f1"
                            strokeOpacity={0.9}
                            strokeStyle="solid"
                          />
                        )}

                        {/* 출발점 */}
                        {recForm.path.length > 0 && (
                          <CustomOverlayMap position={recForm.path[0]} yAnchor={1.5}>
                            <div className="bg-green-500 text-white text-xs font-bold px-2 py-1 rounded-full shadow">출발</div>
                          </CustomOverlayMap>
                        )}

                        {/* 종료점 */}
                        {recForm.path.length > 1 && (
                          <CustomOverlayMap position={recForm.path[recForm.path.length - 1]} yAnchor={1.5}>
                            <div className="bg-red-500 text-white text-xs font-bold px-2 py-1 rounded-full shadow">종료</div>
                          </CustomOverlayMap>
                        )}

                        {/* 1km 마커 */}
                        {kmMarkers.map(m => (
                          <CustomOverlayMap key={m.km} position={m.pos} yAnchor={1.5}>
                            <div className="bg-primary-500 text-white text-xs font-bold w-7 h-7 rounded-full flex items-center justify-center shadow border-2 border-white">
                              {m.km}
                            </div>
                          </CustomOverlayMap>
                        ))}
                      </Map>
                    </div>
                    {recForm.path.length > 0 && (
                      <button
                        onClick={() => setRecForm(p => ({ ...p, path: p.path.slice(0, -1) }))}
                        className="mt-1 text-xs text-slate-400 hover:text-slate-600"
                      >
                        ↩ 마지막 점 취소
                      </button>
                    )}
                  </div>

                  {/* 거리 직접 입력 (경로 없을 때) */}
                  {recForm.path.length < 2 && (
                    <div>
                      <label className="text-sm font-semibold dark:text-dark-text block mb-2">
                        거리 직접 입력 (km)
                      </label>
                      <input
                        type="number"
                        step="0.1"
                        value={recForm.distanceKm}
                        onChange={e => setRecForm(p => ({ ...p, distanceKm: e.target.value }))}
                        placeholder="예: 5.2"
                        className="w-full border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-2.5 bg-transparent dark:text-dark-text focus:outline-none focus:border-primary-400"
                      />
                    </div>
                  )}
                </>
              )}

              {/* 메모 */}
              <div>
                <label className="text-sm font-semibold dark:text-dark-text block mb-2">메모</label>
                <textarea
                  value={recForm.memo}
                  onChange={e => setRecForm(p => ({ ...p, memo: e.target.value }))}
                  placeholder="오늘 운동 기록..."
                  rows={3}
                  className="w-full border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-2.5 bg-transparent dark:text-dark-text focus:outline-none focus:border-primary-400 resize-none"
                />
              </div>

              {/* 저장 버튼 */}
              <button
                onClick={saveRecord}
                className="w-full py-3 bg-primary-500 text-white font-semibold rounded-xl hover:bg-primary-600 transition-colors"
              >
                저장
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ── 목표 설정 모달 ── */}
      {showGoalModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
          <div className="bg-white dark:bg-dark-card rounded-2xl w-full max-w-sm shadow-2xl">
            <div className="p-6 border-b border-slate-200 dark:border-dark-border flex items-center justify-between">
              <h2 className="text-lg font-bold dark:text-dark-text">{year}년 {month}월 목표</h2>
              <button onClick={() => setShowGoalModal(false)} className="text-slate-400 hover:text-slate-600 text-xl">✕</button>
            </div>
            <div className="p-6 flex flex-col gap-4">
              <div>
                <label className="text-sm font-semibold dark:text-dark-text block mb-2">목표 횟수 (회)</label>
                <input
                  type="number"
                  value={goalForm.targetCount}
                  onChange={e => setGoalForm(p => ({ ...p, targetCount: parseInt(e.target.value) || 0 }))}
                  className="w-full border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-2.5 bg-transparent dark:text-dark-text focus:outline-none focus:border-primary-400"
                />
              </div>
              <div>
                <label className="text-sm font-semibold dark:text-dark-text block mb-2">목표 거리 (km, 선택)</label>
                <input
                  type="number"
                  step="0.1"
                  value={goalForm.targetDistanceKm}
                  onChange={e => setGoalForm(p => ({ ...p, targetDistanceKm: e.target.value }))}
                  placeholder="예: 50"
                  className="w-full border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-2.5 bg-transparent dark:text-dark-text focus:outline-none focus:border-primary-400"
                />
              </div>
              <button
                onClick={saveGoal}
                className="w-full py-3 bg-primary-500 text-white font-semibold rounded-xl hover:bg-primary-600 transition-colors"
              >
                저장
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
