import React, { useState, useEffect } from 'react';
import api from '../api/axios';
import { formatNumber, parseNumber } from '../utils/format';

interface FixedCost {
  id: number;
  name: string;
  amount: number;
  isActive: boolean;
  sortOrder: number;
}

export const FixedCostPage = () => {
  const [fixedCosts, setFixedCosts] = useState<FixedCost[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<FixedCost | null>(null);

  const [name, setName] = useState('');
  const [amount, setAmount] = useState('');

  const fetchData = async () => {
    try {
      const res = await api.get('/fixed-costs/member/1');
      setFixedCosts(res.data.data || []);
    } catch (error) {
      console.error('고정비 로드 실패:', error);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const resetForm = () => {
    setName('');
    setAmount('');
    setEditingItem(null);
  };

  const openCreateModal = () => {
    resetForm();
    setIsModalOpen(true);
  };

  const openEditModal = (item: FixedCost) => {
    setEditingItem(item);
    setName(item.name);
    setAmount(formatNumber(item.amount));
    setIsModalOpen(true);
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    const body = {
      memberId: 1,
      name,
      amount: parseNumber(amount),
      isActive: true,
      sortOrder: fixedCosts.length + 1,
    };

    try {
      if (editingItem) {
        await api.put(`/fixed-costs/${editingItem.id}`, body);
      } else {
        await api.post('/fixed-costs', body);
      }
      setIsModalOpen(false);
      resetForm();
      fetchData();
    } catch (error) {
      console.error('저장 실패:', error);
      alert('저장 실패');
    }
  };

  const handleToggleActive = async (item: FixedCost) => {
    try {
      await api.put(`/fixed-costs/${item.id}`, {
        memberId: 1,
        name: item.name,
        amount: item.amount,
        isActive: !item.isActive,
        sortOrder: item.sortOrder,
      });
      fetchData();
    } catch (error) {
      console.error('수정 실패:', error);
    }
  };

  const handleDelete = async (id: number) => {
    if (!window.confirm('삭제하시겠습니까?')) return;
    try {
      await api.delete(`/fixed-costs/${id}`);
      fetchData();
    } catch (error) {
      console.error('삭제 실패:', error);
    }
  };

  const totalActive = fixedCosts
    .filter(f => f.isActive)
    .reduce((sum, f) => sum + f.amount, 0);

  return (
    <div className="space-y-6">
      {/* 헤더 */}
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold dark:text-dark-text">고정비 관리</h2>
          <p className="text-sm text-slate-500 dark:text-dark-muted mt-1">
            활성 고정비 합계:
            <span className="font-bold text-red-500 ml-1">{totalActive.toLocaleString()}원</span>
          </p>
        </div>
        <button
          onClick={openCreateModal}
          className="px-4 py-2 bg-primary-600 text-white rounded-lg font-medium hover:bg-primary-700 transition-colors"
        >
          + 고정비 추가
        </button>
      </div>

      {/* 목록 */}
      <div className="bg-white dark:bg-dark-card rounded-xl shadow-sm border border-slate-200 dark:border-dark-border overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-slate-50 dark:bg-slate-800/50 text-slate-500 dark:text-dark-muted text-xs uppercase font-semibold">
              <th className="px-6 py-3">항목명</th>
              <th className="px-6 py-3 text-right">금액</th>
              <th className="px-6 py-3 text-center">상태</th>
              <th className="px-6 py-3 text-center">관리</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 dark:divide-dark-border">
            {fixedCosts.length > 0 ? (
              fixedCosts.map((item) => (
                <tr key={item.id} className={`transition-colors ${!item.isActive ? 'opacity-40' : ''} hover:bg-slate-50 dark:hover:bg-slate-800/30`}>
                  <td className="px-6 py-4 font-medium dark:text-dark-text">{item.name}</td>
                  <td className="px-6 py-4 text-right font-bold text-red-500">
                    {item.amount.toLocaleString()}원
                  </td>
                  <td className="px-6 py-4 text-center">
                    <button
                      onClick={() => handleToggleActive(item)}
                      className={`px-3 py-1 rounded-full text-xs font-medium transition-colors ${
                        item.isActive
                          ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400'
                          : 'bg-slate-100 text-slate-500 dark:bg-slate-700 dark:text-slate-400'
                      }`}
                    >
                      {item.isActive ? '활성' : '비활성'}
                    </button>
                  </td>
                  <td className="px-6 py-4 text-center">
                    <div className="flex justify-center gap-2">
                      <button
                        onClick={() => openEditModal(item)}
                        className="text-slate-400 hover:text-primary-500 transition-colors"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                        </svg>
                      </button>
                      <button
                        onClick={() => handleDelete(item.id)}
                        className="text-slate-400 hover:text-red-500 transition-colors"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                        </svg>
                      </button>
                    </div>
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={4} className="px-6 py-10 text-center text-slate-400">
                  등록된 고정비가 없습니다.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* 모달 */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
          <div className="bg-white dark:bg-dark-card w-full max-w-sm rounded-2xl shadow-xl p-6 border border-slate-200 dark:border-dark-border">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold dark:text-dark-text">
                {editingItem ? '고정비 수정' : '고정비 추가'}
              </h3>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-600 text-xl">×</button>
            </div>

            <form onSubmit={handleSave} className="space-y-4">
              <div>
                <label className="block text-sm font-medium mb-1 dark:text-dark-muted">항목명</label>
                <input
                  type="text"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full p-2.5 rounded-lg border dark:bg-dark-bg dark:border-dark-border dark:text-dark-text outline-none focus:ring-2 focus:ring-primary-500"
                  placeholder="예: 보험_삼성, 통신비"
                  required
                />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1 dark:text-dark-muted">금액</label>
                <input
                  type="text"
                  value={amount}
                  onChange={(e) => setAmount(formatNumber(e.target.value))}
                  className="w-full p-2.5 rounded-lg border dark:bg-dark-bg dark:border-dark-border dark:text-dark-text outline-none focus:ring-2 focus:ring-primary-500"
                  placeholder="0"
                  required
                />
              </div>
              <div className="flex gap-3 mt-6">
                <button
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="flex-1 py-3 border border-slate-200 dark:border-dark-border rounded-lg font-medium hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors dark:text-dark-text"
                >
                  취소
                </button>
                <button
                  type="submit"
                  className="flex-1 py-3 bg-primary-600 text-white rounded-lg font-bold hover:bg-primary-700 transition-colors"
                >
                  {editingItem ? '수정하기' : '추가하기'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};
